const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '{}';

let findings = [];
try {
  const parsed = JSON.parse(content);
  findings = Array.isArray(parsed) ? parsed : [parsed];
} catch(e) {
  findings = [{ topic: 'Parse Error', summary: content.substring(0,200), relevance: 'LOW', action_required: false }];
}

const today = new Date().toISOString().split('T')[0];
const highFindings = findings.filter(f => f.relevance === 'HIGH');

return [{
  json: {
    date: today,
    findings,
    highCount: highFindings.length,
    highFindings,
    feedEntry: findings.map(f =>
      `---\n[${today}] [SOURCE: ${f.source || 'AI Research'}] [RELEVANCE: ${f.relevance}]\n**Topic:** ${f.topic}\n**Summary:** ${f.summary}\n**Impact on Coprem:** ${f.impact_on_coprem || 'None identified'}\n**Action Required:** ${f.action_required ? 'Yes' : 'No'}\n---`
    ).join('\n')
  }
}];

